import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"PhenoAge (Biological Age)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/phenoage.md","filePath":"guide/phenoage.md","lastUpdated":1773398769000}'),i={name:"guide/phenoage.md"};function n(s,e,l,h,d,g){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="phenoage-biological-age" tabindex="-1">PhenoAge (Biological Age) <a class="header-anchor" href="#phenoage-biological-age" aria-label="Permalink to &quot;PhenoAge (Biological Age)&quot;">​</a></h1><p>PhenoAge is a calculated estimate of your biological age — how old your body appears to be based on blood markers — as opposed to your chronological age. getbased computes it automatically using the formula published by Morgan Levine et al. in 2018.</p><h2 id="what-it-measures" tabindex="-1">What It Measures <a class="header-anchor" href="#what-it-measures" aria-label="Permalink to &quot;What It Measures&quot;">​</a></h2><p>PhenoAge does not replace any single biomarker. Instead, it combines nine routine blood markers into a single number that correlates with disease risk, functional decline, and mortality better than chronological age alone. In practical terms: a PhenoAge lower than your actual age suggests your biology is aging more slowly than average; a higher PhenoAge suggests the opposite.</p><h2 id="the-nine-biomarkers" tabindex="-1">The Nine Biomarkers <a class="header-anchor" href="#the-nine-biomarkers" aria-label="Permalink to &quot;The Nine Biomarkers&quot;">​</a></h2><p>PhenoAge is calculated from:</p><table tabindex="0"><thead><tr><th>Marker</th><th>Category</th></tr></thead><tbody><tr><td>Albumin</td><td>Liver / Protein</td></tr><tr><td>Creatinine</td><td>Kidney</td></tr><tr><td>Glucose (fasting)</td><td>Metabolic</td></tr><tr><td>hsCRP (C-reactive protein)</td><td>Inflammation</td></tr><tr><td>Lymphocytes %</td><td>Immune</td></tr><tr><td>MCV (mean corpuscular volume)</td><td>Hematology</td></tr><tr><td>RDW-CV (red cell distribution width)</td><td>Hematology</td></tr><tr><td>ALP (alkaline phosphatase)</td><td>Liver</td></tr><tr><td>WBC (white blood cells)</td><td>Immune</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>PhenoAge requires <strong>all nine markers</strong> to be present for a given date. If any one of them is missing, no value is calculated for that draw — the detail view shows exactly which inputs are missing. It also requires your <strong>date of birth</strong> to be set in Settings → Profile.</p><p><strong>hs-CRP required</strong>: PhenoAge specifically needs high-sensitivity CRP (hs-CRP), not standard CRP. These are different assays — standard CRP lacks the precision needed for the calculation. Make sure your lab report includes hs-CRP.</p></div><h2 id="where-to-find-it" tabindex="-1">Where to Find It <a class="header-anchor" href="#where-to-find-it" aria-label="Permalink to &quot;Where to Find It&quot;">​</a></h2><p>PhenoAge appears as a marker in the <strong>Aging</strong> or <strong>Calculated</strong> category in the sidebar. Click it to open the detail view, which shows:</p><ul><li>Your PhenoAge at each draw date</li><li>A <strong>gray dashed line</strong> representing your chronological age at the time of each draw</li><li>The gap between the two lines — the key number to watch</li></ul><h2 id="interpreting-your-score" tabindex="-1">Interpreting Your Score <a class="header-anchor" href="#interpreting-your-score" aria-label="Permalink to &quot;Interpreting Your Score&quot;">​</a></h2><p>There is no fixed reference range for PhenoAge the way there is for, say, LDL cholesterol. What matters is the relationship between your PhenoAge and your actual age:</p><ul><li><strong>PhenoAge &lt; chronological age</strong> — biological age is tracking younger than calendar age</li><li><strong>PhenoAge = chronological age</strong> — biological age is roughly average</li><li><strong>PhenoAge &gt; chronological age</strong> — biological age is tracking older than calendar age</li></ul><p>The trend over time matters more than any single reading. Consistent improvements across multiple draws — even small ones — are meaningful.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The markers that most strongly influence PhenoAge are hs-CRP (inflammation) and albumin (nutrition/liver health). If your PhenoAge is higher than expected, those are often the first places to investigate.</p></div><h2 id="in-ai-chat" tabindex="-1">In AI Chat <a class="header-anchor" href="#in-ai-chat" aria-label="Permalink to &quot;In AI Chat&quot;">​</a></h2><p>When you discuss PhenoAge in the AI chat, the AI receives your chronological age alongside the PhenoAge values and can interpret the gap, note the trend direction, and suggest which contributing markers to focus on.</p>',18)])])}const p=t(i,[["render",n]]);export{u as __pageData,p as default};
